import { useState } from 'react';
import { Link } from 'react-router-dom';


import Input from './components/reg-log-components/input';
import Checkbox from './components/reg-log-components/checkbox';
import Button from './components/reg-log-components/button';

const Login = ({ onLogin, changeOnRegisterPage }) => {

    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');

  return (
    <div>
      <div>
        <div>
          <header>Sign In</header>

          <Input
            icon="/images/icons/username.svg"
            alt="username"
            placeholder="Enter Username"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
          />

          <Input
            icon="/images/icons/black_password.svg"
            alt="password"
            placeholder="Enter Password"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          <Checkbox text="Remember Me"/>

          <Button text="Login" onClick={onLogin}/>

          <div>
            <label>Or, Login with</label>
            <img src="/images/icons/facebook.svg" alt="facebook" />
            <img src="/images/icons/google.svg" alt="google" />
            <img src="/images/icons/x.svg" alt="x" />
          </div>

          <div>
            <label>Don't have an account? </label>
            <label onClick={changeOnRegisterPage}><Link to="/register">Create One</Link></label>
          </div>
        </div>

        <div>
          <img src="/images/login.png" alt="login"/>
        </div>
      </div>
    </div>
  );
};

export default Login;
